import{_ as i,o as l,c as e,a3 as t}from"./chunks/framework.CVjg771q.js";const p=JSON.parse('{"title":"象数理","description":"象数理是一条更适合《易经》入门的理解路径，先看卦象，再看数与结构，最后回到义理。","frontmatter":{"title":"象数理","description":"象数理是一条更适合《易经》入门的理解路径，先看卦象，再看数与结构，最后回到义理。","category":"concept","aliases":["象数理","易经象数理","xiang shu li"]},"headers":[],"relativePath":"yijing/basics/concepts/xiang-shu-li.md","filePath":"yijing/basics/concepts/xiang-shu-li.md","lastUpdated":1778243500000}'),r={name:"yijing/basics/concepts/xiang-shu-li.md"};function n(o,a,s,h,c,d){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="象数理" tabindex="-1">象数理 <a class="header-anchor" href="#象数理" aria-label="Permalink to &quot;象数理&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>“象数理”更适合作为《易经》入门时的整理框架：</p><ul><li>象：先看卦象、爻象、方位、动静与关系呈现</li><li>数：再看阴阳爻位、卦序、往来、消长与结构节奏</li><li>理：最后看这些象与数背后说明了什么义理</li></ul><p>对初学者来说，这条路径比一开始就急着谈“怎么用”更稳，也能避免把《易经》概念和术数里的“体用、生克”等体系混在一起。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>只谈象，不看数，最后只剩符号印象</li><li>只谈数，不通理，最后容易变成机械排布</li><li>只谈理，不回到象与数，最后容易悬空</li></ul><p>较好的读法，是让三者互相牵引，而不是任意切开。</p><h2 id="在原典中的语境" tabindex="-1">在原典中的语境 <a class="header-anchor" href="#在原典中的语境" aria-label="Permalink to &quot;在原典中的语境&quot;">​</a></h2><ul><li>《周易》本身从卦象、爻象出发，这是“象”的基础。</li><li>阴阳爻、六位、卦序、错综互变等结构，让“数”不只是数字，而是变化的秩序感。</li><li>《彖传》《象传》《系辞》不断把象与数推向义理。</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：后续可把自己读某一卦时“从象入手、由数见结构、再回到义理”的过程写成示例。</p><h2 id="关联页面" tabindex="-1">关联页面 <a class="header-anchor" href="#关联页面" aria-label="Permalink to &quot;关联页面&quot;">​</a></h2><ul><li><a href="/Dao/yijing/hexagrams/">六十四卦目录</a></li><li><a href="/Dao/yijing/basics/concepts/bian-yi">变易</a></li><li><a href="/Dao/yijing/basics/concepts/yin-yang">阴阳</a></li><li><a href="/Dao/topics/xiang-shu-li">专题：象数理</a></li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li>《象传》</li><li>《系辞上传》</li></ul>',16)])])}const _=i(r,[["render",n]]);export{p as __pageData,_ as default};
